//! Auto-generated `#[pyclass]` subclasses of `PyExpression` — one per `Expression` variant.
//!
//! Generated by the `define_expression_subclasses!` macro below.

use crate::expr::PyExpression;
use polyglot_sql::Expression;
use pyo3::prelude::*;

macro_rules! define_expression_subclasses {
    ($($variant:ident),* $(,)?) => {
        // 1. Generate empty #[pyclass] structs extending PyExpression
        $(
            #[pyclass(extends = PyExpression, module = "polyglot_sql")]
            pub struct $variant {}
        )*

        // 2. Dispatcher: wrap an Expression into the correct typed Python subclass
        pub fn wrap_expression(py: Python<'_>, expr: Expression) -> PyResult<Py<PyAny>> {
            let base = PyExpression::from_inner(expr);
            match &base.inner {
                $(
                    Expression::$variant(_) => {
                        Py::new(
                            py,
                            PyClassInitializer::from(base).add_subclass($variant {}),
                        )
                        .map(|p| p.into_any())
                    }
                )*
            }
        }

        // 3. Dispatcher with parent tracking
        pub fn wrap_expression_with_parent(
            py: Python<'_>,
            expr: Expression,
            parent: Py<PyAny>,
            arg_key: &str,
        ) -> PyResult<Py<PyAny>> {
            let base = PyExpression::from_inner_with_parent(expr, parent, arg_key);
            match &base.inner {
                $(
                    Expression::$variant(_) => {
                        Py::new(
                            py,
                            PyClassInitializer::from(base).add_subclass($variant {}),
                        )
                        .map(|p| p.into_any())
                    }
                )*
            }
        }

        // 4. Register all subclass types on the module
        pub fn register_expression_subclasses(m: &Bound<'_, PyModule>) -> PyResult<()> {
            $(m.add_class::<$variant>()?;)*
            Ok(())
        }
    };
}

